import requests

def test_fraud_alert_invalid_response_value(base_url, auth_token, test_alert_id):
    headers = {'Authorization': f'Bearer {auth_token}'}
    payload = {'response': 'maybe'}

    resp = requests.post(
        f'{base_url}/alerts/{test_alert_id}',
        json=payload,
        headers=headers,
        timeout=5
    )
    assert resp.status_code == 400
    data = resp.json()
    assert 'invalid' in data.get('error', '').lower()

import requests

def test_fraud_alert_unauthenticated_access(base_url, test_alert_id):
    payload = {'response': 'confirm'}

    resp = requests.post(
        f'{base_url}/alerts/{test_alert_id}',
        json=payload,
        timeout=5
    )
    assert resp.status_code == 401
